/// contained in the type to avoid.
///
/// Example to find all the Faces in the Shape S :
///
/// TopExp_Explorer Ex;
/// for (Ex.Init(S,TopAbs_FACE); Ex.More(); Ex.Next()) {
/// ProcessFace(Ex.Current());
