/// while (Ex.More()) {
/// ProcessFace(Ex.Current());
/// Ex.Next();
/// }
///
/// To find all the vertices which are not in an edge :
///
/// for (Ex.Init(S,TopAbs_VERTEX,TopAbs_EDGE); ...)
///
/// To  find all the faces  in   a SHELL, then all the
/// faces not in a SHELL :
///
/// TopExp_Explorer Ex1, Ex2;
